(function(){"use strict";const t=new Map,n=new Map;self.onmessage=({data:s})=>{if(s.type==="clear"){t.clear(),n.clear();return}if(s.type==="buildAdjacency"){t.clear(),n.clear();for(const e of s.edges)n.has(e.source)||n.set(e.source,new Set),n.get(e.source).add(e.target),t.has(e.target)||t.set(e.target,new Set),t.get(e.target).add(e.source);const o={type:"ready",nodeCount:new Set([...t.keys(),...n.keys()]).size};self.postMessage(o)}if(s.type==="neighbors"){const c=s.limit??20,o=t.get(s.nodeId),e=n.get(s.nodeId),r={type:"neighbors",nodeId:s.nodeId,inlinks:o?[...o].slice(0,c):[],outlinks:e?[...e].slice(0,c):[]};self.postMessage(r)}}})();
